def can_build_fence(a):
    # Check if a is a divisor of 360 and if a is less than 180
    return 360 % a == 0 and a < 180

def main():
    import sys
    input = sys.stdin.read
    data = input().split()

    t = int(data[0])
    results = []

    for i in range(1, t + 1):
        a = int(data[i])
        if can_build_fence(a):
            results.append("YES")
        else:
            results.append("NO")

    for result in results:
        print(result)

if __name__ == "__main__":
    main()
